const items = $input.all();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const recentEntries = items.filter(item => {
  const raw = item.json.created_at || item.json.date;
  if (!raw) return false;
  const d = new Date(raw);
  return !isNaN(d.getTime()) && d >= sevenDaysAgo;
});

if (recentEntries.length === 0) {
  throw new Error('No logbook entries found in the last 7 days. Nothing to brief.');
}

const systemPrompt = `You are a restaurant operations analyst preparing a weekly brief for a General Manager.

You will receive the formatted logbook entries from the past seven days (up to 14 shifts: AM and PM for each day). Your job is to synthesize these into a concise, insight-driven brief that helps the GM prepare for their weekly team meeting.

Return a weekly brief with exactly these five sections. Use bullet points. Prioritize signal over volume.

### Weekly Snapshot
- Days covered and total shifts reviewed
- Total sales for the week with a one-line characterization
- Highlight the single best-performing shift and the single weakest shift

### Recurring Operational Themes
- Patterns that appeared across 2 or more shifts (mention count)
- Only include themes that appeared in 2+ shifts

### Staffing Observations
- Patterns in staffing levels across the week
- Any roles consistently over or under relative to volume
- AM vs PM differences if notable

### Sales Trends
- Day-over-day sales pattern
- Any days materially different from weekly average (flag if >15% above or below)
- AM vs PM split if meaningful

### Unresolved Items & GM Recommendations
- Action items or follow-ups appearing in more than one shift and not resolved
- Two or three specific recommendations for the GM's weekly meeting agenda

Base all observations strictly on the logbook data provided. Maintain a professional, analytical tone.`;

const weekStart = sevenDaysAgo.toISOString().split('T')[0];
const weekEnd = now.toISOString().split('T')[0];

const entriesText = recentEntries.map((item, i) => {
  const shift = item.json.shift_type || 'Unknown';
  const date = item.json.date || 'Unknown date';
  const entry = item.json.ai_formatted_entry || '(no formatted entry)';
  return `--- Entry ${i + 1}: ${shift} Shift | ${date} ---\n${entry}`;
}).join('\n\n');

const userPrompt = `Please synthesize the following ${recentEntries.length} logbook entries (${weekStart} to ${weekEnd}) into a GM weekly brief.\n\n${entriesText}`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    entryCount: recentEntries.length,
    weekStart,
    weekEnd
  }
}];

const claudeJson = $input.first().json;
const meta = $('Build Weekly Prompt').first().json;

const briefText = claudeJson.content[0].text;

const toSlack = (text) => text
  .replace(/^#{1,3} (.+)$/gm, '*$1*')
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/^---+$/gm, '─────────────')
  .trim();

const toPlainText = (text) => text
  .replace(/^#{1,3} (.+)$/gm, '\n$1\n' + '-'.repeat(30))
  .replace(/\*\*(.+?)\*\*/g, '$1')
  .replace(/^---+$/gm, '-'.repeat(30))
  .trim();

return [{
  json: {
    briefText,
    weekStart: meta.weekStart,
    weekEnd: meta.weekEnd,
    entryCount: meta.entryCount,
    slackFormatted: `*Weekly GM Brief — ${meta.weekStart} to ${meta.weekEnd}*\n_(${meta.entryCount} shifts reviewed)_\n\n${toSlack(briefText)}`,
    emailSubject: `Weekly GM Brief — ${meta.weekStart} to ${meta.weekEnd}`,
    emailBody: toPlainText(briefText)
  }
}];
